package com.example.app.network

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

class UserRepository {
    
    private val apiService: UserApiService by lazy {
        NetworkModule.createService(UserApiService::class.java)
    }
    
    suspend fun getUserProfile(userId: String): ApiResult<UserProfile> {
        return withContext(Dispatchers.IO) {
            try {
                val response = apiService.getUserProfile(userId)
                if (response.isSuccessful && response.body() != null) {
                    ApiResult.Success(response.body()!!)
                } else {
                    ApiResult.Error(
                        message = response.message() ?: "Unknown error",
                        code = response.code()
                    )
                }
            } catch (e: Exception) {
                ApiResult.Error(message = e.message ?: "Network error")
            }
        }
    }
    
    suspend fun getUsers(page: Int = 1, limit: Int = 20): ApiResult<UsersResponse> {
        return withContext(Dispatchers.IO) {
            try {
                val response = apiService.getUsers(page, limit)
                if (response.isSuccessful && response.body() != null) {
                    ApiResult.Success(response.body()!!)
                } else {
                    ApiResult.Error(
                        message = response.message() ?: "Unknown error",
                        code = response.code()
                    )
                }
            } catch (e: Exception) {
                ApiResult.Error(message = e.message ?: "Network error")
            }
        }
    }
}

